#include <bits/stdc++.h>

using namespace std;

void dispose(char c) {
	if (c == '[' || c == ']')
		cout << "[]";
	else if (c == '(' || c == ')')
		cout << "()";
}
int main() {
	string str;
	getline(cin, str);
	vector<int> vc1(str.size(), 0);
	vector<char> vc2(str.size());
	for (int i = 0; i < str.size(); i++) {
		if (str[i] == '[' || str[i] == '(') {
			vc2[i] = 'z';
		}
		if (str[i] == ']' || str[i] == ')') {
			vc2[i] = 'y';
		}
	}

	for (int i = 0; i < str.size(); i++) {
		if (vc2[i] == 'y') {
			for (int j = i; j >= 0; j--) {
				if (vc2[j] == 'z' && vc1[j] == 0) {
					if (str[i] == ']' && str[j] == '[' || str[i] == ')' && str[j] == '(') {
						vc1[i] = vc1[j] = 1;
					}
					break;
				}
			}
		}
	}

	for (int i = 0; i < str.size(); i++) {
		if (vc1[i] == 0) {
			dispose(str[i]);
			continue;
		}
		cout<<str[i];
	}
	return 0;
}
